// Base AST node classes --------------------------------------------------
class Stmt {
  public:
  virtual std::any accept(StmtVisitorAny& visitor) = 0;
  virtual void accept(StmtVisitorVoid& visitor) = 0;

  // To call a typed/concrete visitor without having to write the ugly std::any stuff.
  template <typename R>
  R accept(StmtVisitor<R>& visitor) {
    return std::any_cast<R>(accept(static_cast<StmtVisitorAny&>(visitor)));
  }

  virtual ~Stmt() = default;
};

class Expr {
  public:
  virtual std::any accept(ExprVisitorAny& visitor) = 0;
  virtual void accept(ExprVisitorVoid& visitor) = 0;

  // To call a typed/concrete visitor without having to write the ugly std::any stuff.
  template <typename R>
  R accept(ExprVisitor<R>& visitor) {
    return std::any_cast<R>(accept(static_cast<ExprVisitorAny&>(visitor)));
  }

  virtual ~Expr() = default;
};

